public class ParseBenchmarkTest {

  private static Path tempDir;
  private static File tempZipFile;
  private static File resourceFile;

  @BeforeAll
  static void createTestZipFile() throws IOException {
    tempDir = Files.createTempDirectory("ParseBenchmarkTest");
    tempZipFile = new File(tempDir.toFile(), "ParseBenchmarkData.zip");
    try (ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(tempZipFile))) {
      ZipEntry entry = new ZipEntry("testFile.txt");
      zos.putNextEntry(entry);
      byte[] data = "Hello, world!".getBytes(StandardCharsets.UTF_8);
      zos.write(data, 0, data.length);
      zos.closeEntry();
    }

    // Instead of calling getResourceFile (which fails due to URI non-hierarchical),
    // directly set resourceFile to the tempZipFile path.
    resourceFile = tempZipFile;
  }

  @AfterAll
  static void cleanup() throws IOException {
    if (resourceFile != null && resourceFile.exists()) {
      Files.deleteIfExists(resourceFile.toPath());
      // Try to delete parent dirs if empty
      File parent = resourceFile.getParentFile();
      while (parent != null && parent.exists() && parent.list().length == 0) {
        parent.delete();
        parent = parent.getParentFile();
      }
    }
    if (tempZipFile != null && tempZipFile.exists()) {
      Files.deleteIfExists(tempZipFile.toPath());
    }
    if (tempDir != null && tempDir.toFile().exists()) {
      Files.deleteIfExists(tempDir);
    }
  }

  @Test
  void resourceToString_readsZipEntryContent() throws Exception {
    Method resourceToString = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToString.setAccessible(true);
    String content = (String) resourceToString.invoke(null, "testFile.txt");
    assertEquals("Hello, world!", content);
  }

  @Test
  void resourceToString_throwsExceptionForMissingEntry() throws Exception {
    Method resourceToString = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToString.setAccessible(true);

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
      resourceToString.invoke(null, "nonexistent.txt");
    });

    // Optionally, you can check cause or message here if needed
  }
}
